function feedback(str,x,y)global scr visual paramsbounds = Screen(scr.main,'TextBounds',str);pt = 0.012*length(str); % presentation timex  = x-bounds(3)/2;     % x positiony  = y-bounds(4)/2;     % y positionc  = visual.fgColor(1); % colorWaitSecs(0.2);nBlank = round(0.20*1/scr.fd); % fade out takes 0.2 secsrubber([]);% Screen('TextFont',scr.main,'Arial');Screen('TextSize',scr.main,visual.ppd.*.5);            Screen(scr.main,'Drawtext',str,x,y,c);vbl = Screen(scr.main,'Flip');WaitSecs(round(0.2/scr.fd)*scr.fd - scr.fd);for i = 1:nBlank	c = round(visual.fgColor(1)+(visual.bgColor(1)-visual.fgColor(1))*i/nBlank);	 % rubber([x y x+width y+const.FONT_SIZE]);	Screen(scr.main,'Drawtext',str,x,y,c);	    Screen(scr.main,'Flip',vbl + (i-0.5)*scr.fd);endrubber([]);Screen(scr.main,'Flip');